以下是用C#的方式求解已知五边形五条边长和一个角度，求其他角度的代码示例：

```csharp
using System;

public class PentagonSolver {
    public static void Solve(double a, double b, double c, double d, double e, double angleA, out double angleB, out double angleC, out double angleD, out double angleE) {
        double cosA = Math.Cos(angleA * Math.PI / 180.0);
        double cosB = (a * a + c * c - b * b) / (2 * a * c);
        double cosC = (a * a + d * d - c * c) / (2 * a * d);
        double cosD = (a * a + e * e - d * d) / (2 * a * e);
        double cosE = (b * b + e * e - c * c) / (2 * b * e);

        double sinA = Math.Sin(angleA * Math.PI / 180.0);
        double sinB = sinA * b / a;
        double sinC = sinA * c / a;
        double sinD = sinA * d / a;
        double sinE = sinA * e / a;

        angleB = Math.Asin(sinB) * 180.0 / Math.PI;
        angleC = Math.Asin(sinC) * 180.0 / Math.PI;
        angleD = Math.Asin(sinD) * 180.0 / Math.PI;
        angleE = Math.Asin(sinE) * 180.0 / Math.PI;

        if (cosB < 0) angleB = 180.0 - angleB;
        if (cosC < 0) angleC = 180.0 - angleC;
        if (cosD < 0) angleD = 180.0 - angleD;
        if (cosE < 0) angleE = 180.0 - angleE;
    }
}

// 使用示例
double a = 4, b = 5, c = 6, d = 7, e = 8, angleA = 35;
double angleB, angleC, angleD, angleE;
PentagonSolver.Solve(a, b, c, d, e, angleA, out angleB, out angleC, out angleD, out angleE);
Console.WriteLine("B = " + angleB);
Console.WriteLine("C = " + angleC);
Console.WriteLine("D = " + angleD);
Console.WriteLine("E = " + angleE);
```

以上代码中，我们使用了Math库中的Cos、Sin、Asin等函数来进行计算，并在最后加入了一个示例来演示如何使用PentagonSolver类求解。

在Unity中已知三个点，可以使用Vector3的静态方法AngleBetween()来获取它们间的夹角，代码示例如下：

```csharp
using UnityEngine;

public class AngleBetweenPoints : MonoBehaviour
{
    public Transform point1, point2, point3; // 三个点
    public GameObject debugObject; // 用于显示夹角的调试物体

    void Update()
    {
        Vector3 dir1 = point2.position - point1.position;
        Vector3 dir2 = point2.position - point3.position;

        // 获取角度并设置调试物体的旋转
        float angle = Vector3.Angle(dir1, dir2);
        debugObject.transform.rotation = Quaternion.LookRotation(dir1);
        debugObject.transform.Rotate(Vector3.up, -angle / 2.0f); // 将物体的初始朝向向上旋转一半的角度

        Debug.Log("夹角: " + angle);
    }
}
```

以上代码中，我们先定义了三个点变量point1、point2、point3，它们分别代表了三个点的Transform组件。在Update()函数中，我们首先计算出point1->point2和point3->point2两个向量，然后使用Vector3.Angle()方法计算出它们间的夹角angle，同时将调试物体debugObject旋转到point1->point2向量的方向上，并再向上旋转一半的夹角以便清晰显示夹角方向。最后在控制台输出夹角的数值。

使用时，只需要将AngleBetweenPoints脚本挂载到一个GameObject上，并将三个点的Transform赋值给point1、point2、point3即可。这样每帧都会计算并输出夹角值，并将一个调试物体旋转到对应方向。

以下是用C#的方式求解已知五边形五条边长度，求五边形五个内角的代码示例：

```csharp
using System;

public class PentagonSolver {
    public static void Solve(double a, double b, double c, double d, double e, out double angleA, out double angleB, out double angleC, out double angleD, out double angleE) {
        // 求两个相对的内角
        double cosA = (b * b + c * c - a * a) / (2 * b * c);
        double cosC = (a * a + d * d - c * c) / (2 * a * d);
        double angleAdeg = Math.Acos(cosA) * 180.0 / Math.PI;
        double angleCdeg = Math.Acos(cosC) * 180.0 / Math.PI;

        // 计算平均内角和四个顶点的内角
        double averageAngle = 108.0;
        double sumAngleABDE = 540.0 - angleAdeg - angleCdeg - 3 * averageAngle;
        double angleABDE = sumAngleABDE / 4;
        angleA = angleAdeg;
        angleC = angleCdeg;

        // 均分四个顶点的内角
        angleB = angleABDE;
        angleD = angleABDE;
        angleE = angleABDE;
    }
}

// 使用示例
double a = 1, b = 2, c = 3, d = 4, e = 5;
double A, B, C, D, E;
PentagonSolver.Solve(a, b, c, d, e, out A, out B, out C, out D, out E);
Console.WriteLine("内角A = " + A);
Console.WriteLine("内角B = " + B);
Console.WriteLine("内角C = " + C);
Console.WriteLine("内角D = " + D);
Console.WriteLine("内角E = " + E);
```

以上代码中，我们使用了Math库中的Cos、Acos等函数来进行计算，并在最后加入了一个示例来演示如何使用PentagonSolver类求解。
